FROM jsonb_to_recordset('[{"id": "cap-114-english-reading-029", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "What do the comics tell us?", "options": ["Enjoy life while we can.", "Follow the old ways of life.", "Save our planet before it’s too late.", "Treat others the way we want to be treated."], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-29", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 29, "raw_text": "29. What do the comics tell us?\n    (A) Enjoy life while we can.\n    (B) Follow the old ways of life.\n    (C) Save our planet before it’s too late.\n    (D) Treat others the way we want to be treated.\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "漫畫從「樹木充足→過度砍伐→生態崩潰→人類滅絕」最後以「Let''s not make Earth, our only home, another Easter Island」作結，呼籲珍惜地球資源，故 (C) Save our planet before it''s too late 正確。(A) 即時行樂與警示主旨相反；(B) 守舊；(D) 待人之道皆與環境議題無關。"}, {"id": "cap-114-english-reading-030", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "What can we learn about the people in the comics?", "options": ["They made fire before starting a fight.", "They fought for land and plants all the time.", "They prayed to the statues beside a large fire.", "They used statues to show how strong they were."], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-29", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 30, "raw_text": "30. What can we learn about the people in the comics?\n    (A) They made fire before starting a fight.\n    (B) They fought for land and plants all the time.\n    (C) They prayed to the statues beside a large fire.\n    (D) They used statues to show how strong they were.\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "原文「The statues were moved to fighting grounds to show their power」直接說明石像被移到爭奪場以展示力量，故 (D) They used statues to show how strong they were 正確。(A) 文未提先升火再戰鬥；(B) 是為水與食物而戰非土地與植物；(C) 未提祭拜。"}, {"id": "cap-114-english-reading-031", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "What does did it in Picture 7 mean?", "options": ["Fall to the ground.", "Cut down the last trees.", "Move the statues to fighting grounds.", "Understand how important trees were."], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-29", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 31, "raw_text": "31.    What does did it in Picture 7 mean?\n       (A) Fall to the ground.\n       (B) Cut down the last trees.\n       (C) Move the statues to fighting grounds.\n       (D) Understand how important trees were.\n\n\n\n\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "Picture 7 緊接「Those who cut down the last trees surely understood…—but still, they did it」，「did it」即指砍下最後的樹，故 (B) Cut down the last trees 正確。(A) fall 是後文人類的隱喻；(C)(D) 與時序及文意不合。"}, {"id": "cap-114-english-reading-032", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "What did Ariely try to find out in the origami study?", "options": ["If he could stop the IKEA effect.", "Why people love making origami.", "Why IKEA furniture is so famous.", "If anyone shared his IKEA experience."], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-32", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 32, "raw_text": "32. What did Ariely try to find out in the origami study?\n    (A) If he could stop the IKEA effect.\n    (B) Why people love making origami.\n    (C) Why IKEA furniture is so famous.\n    (D) If anyone shared his IKEA experience.\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "原文「Ariely wanted to know if anyone shared his feelings, so he did a fun origami study」直接點出實驗目的是驗證「是否有人和我（Ariely 對 IKEA 的）感受相同」，故 (D) If anyone shared his IKEA experience 正確。(A) 沒有要阻止 IKEA 效應；(B)(C) 都非實驗主旨。"}, {"id": "cap-114-english-reading-033", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "Which is true about the origami study?", "options": ["Buyers would spend less on builders’ origami than builders would.", "Builders and buyers needed to decide a price on the origami they made.", "Builders knew others would not pay as much for the origami as they would.", "Buyers would spend more on builders’ origami after knowing how they were made."], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-32", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 33, "raw_text": "33. Which is true about the origami study?\n    (A) Buyers would spend less on builders’ origami than builders would.\n    (B) Builders and buyers needed to decide a price on the origami they made.\n    (C) Builders knew others would not pay as much for the origami as they would.\n    (D) Buyers would spend more on builders’ origami after knowing how they were made.\n\n\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "原文 builders 願花 25 cents、buyers 只願花 5 cents，正是「buyers 出價低於 builders」，故 (A) Buyers would spend less on builders'' origami than builders would 正確。(B) 買家不需自己定價；(C) builders 反而以為他人會認可高價；(D) 文中未討論「知道製作過程後」的影響。"}, {"id": "cap-114-english-reading-034", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "Jerry just can’t get his daughter Mia to eat more vegetables at dinner.  Every time he tries\nto do so, there is always a lot of shouting and crying.  If Jerry wants to have Mia eat more\nvegetables by using the IKEA effect, what should he do?", "options": ["Tell Mia that he cooks the vegetables just for her.", "Ask Mia to help him cook vegetables for her meal.", "Give Mia her favorite candy after she eats vegetables.", "Ask Mia what vegetables she likes and cook them for her."], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-32", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 34, "raw_text": "34. Jerry just can’t get his daughter Mia to eat more vegetables at dinner.  Every time he tries\n    to do so, there is always a lot of shouting and crying.  If Jerry wants to have Mia eat more\n    vegetables by using the IKEA effect, what should he do?\n    (A) Tell Mia that he cooks the vegetables just for her.\n    (B) Ask Mia to help him cook vegetables for her meal.\n    (C) Give Mia her favorite candy after she eats vegetables.\n    (D) Ask Mia what vegetables she likes and cook them for her.\n\n\n\n\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "IKEA 效應指「親手投入製作後對成品的偏愛增加」。Jerry 想用此效應讓 Mia 多吃蔬菜，最有效是「讓 Mia 一起參與烹煮」，故 (B) Ask Mia to help him cook vegetables for her meal 正確。(A) 只是聲明；(C) 是獎勵機制；(D) 是迎合喜好，皆未涉及親身投入製作。"}, {"id": "cap-114-english-reading-035", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "What is the reading mainly about?", "options": ["The tips on using a picture to tell a story.", "The change that electricity brought to people’s lives.", "The history behind the picture of a UK electricity worker.", "The story of a famous UK electricity worker from the 1970s."], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-35", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 35, "raw_text": "35. What is the reading mainly about?\n    (A) The tips on using a picture to tell a story.\n    (B) The change that electricity brought to people’s lives.\n    (C) The history behind the picture of a UK electricity worker.\n    (D) The story of a famous UK electricity worker from the 1970s.\n\n\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "全文以「1970 年代英國電力工人罷工照片」為核心，敘述照片背後的兩次罷工與政府應對的歷史，故 (C) The history behind the picture of a UK electricity worker 正確。(A) 是看圖技巧；(B) 是電力對生活影響；(D) 是個別工人故事，皆非主軸。"}, {"id": "cap-114-english-reading-036", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "In the UK in the 1970s, what did people most likely think of the UK electricity workers?", "options": ["They were not brave enough to fix their problems.", "They worked like robots and never learned to change.                   likely 可能", "They were asking too much and did not know when to stop.", "They did not care whether their job might hurt people’s health."], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-35", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 36, "raw_text": "36. In the UK in the 1970s, what did people most likely think of the UK electricity workers?\n    (A) They were not brave enough to fix their problems.\n    (B) They worked like robots and never learned to change.                   likely 可能\n    (C) They were asking too much and did not know when to stop.\n    (D) They did not care whether their job might hurt people’s health.\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "原文「For months, people were paying the price while the electricity workers were fighting for their wish」加上民眾因停電生活困頓，可推當時人們認為工人「索求過多、不知節制」，故 (C) They were asking too much and did not know when to stop 正確。(A) 不是不夠勇敢；(B) 不是死板；(D) 健康問題未在此被指責。"}, {"id": "cap-114-english-reading-037", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "Why does the writer put the “ ” mark around the word dark in the last sentence?", "options": ["To say that the “dark” time was actually not dark.", "To tell people that the word was said by the government.", "To mean both the days without lights and the difficult lives people lived.", "To show that the government and the electricity workers both lost their fights."], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-35", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 37, "raw_text": "37.   Why does the writer put the “ ” mark around the word dark in the last sentence?\n      (A) To say that the “dark” time was actually not dark.\n      (B) To tell people that the word was said by the government.\n      (C) To mean both the days without lights and the difficult lives people lived.\n      (D) To show that the government and the electricity workers both lost their fights.\n\n\n\n\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "「dark」加引號的雙關用法，既指字面缺電的黑暗，又指人們生活上的艱困期，故 (C) To mean both the days without lights and the difficult lives people lived 正確。(A) 否定字面意義不符；(B) 並非引述政府用語；(D) 兩方輸贏未在此句點出。"}, {"id": "cap-114-english-reading-038", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "(A) starts             (B) started              (C) has started      (D) will start", "options": ["", "", "", ""], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-38", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["option_incomplete", "option_image"], "parse_confidence": 0.4, "original_question_number": 38, "raw_text": "38. (A) starts             (B) started              (C) has started      (D) will start\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-english-reading-039", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "(A) he got quite scared of two things", "options": ["", "he still couldn’t understand two things", "he couldn’t stop thinking about two things", "he did two things that would change his life"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-38", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["option_incomplete"], "parse_confidence": 0.75, "original_question_number": 39, "raw_text": "39. (A) he got quite scared of two things\n    (B) he still couldn’t understand two things\n    (C) he couldn’t stop thinking about two things\n    (D) he did two things that would change his life\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-english-reading-040", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "(A) should be spent helping his mom", "options": ["", "should be a time of welcoming a new start", "should not be about him, but about his mom", "should not be celebrated for just one day, but for nine months"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-38", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["option_incomplete"], "parse_confidence": 0.75, "original_question_number": 40, "raw_text": "40. (A) should be spent helping his mom\n    (B) should be a time of welcoming a new start\n    (C) should not be about him, but about his mom\n    (D) should not be celebrated for just one day, but for nine months\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-english-reading-041", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "(A) first              (B) last                 (C) only             (D) other", "options": ["", "", "", ""], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-38", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["option_incomplete", "option_image"], "parse_confidence": 0.4, "original_question_number": 41, "raw_text": "41. (A) first              (B) last                 (C) only             (D) other\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-114-english-reading-042", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "(A) made his head hurt                          (B) made his heart sing", "options": ["", "", "made him change his mind", "made him give up baking"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": "cap-114-english-reading-passage-38", "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": ["option_incomplete"], "parse_confidence": 0.75, "original_question_number": 42, "raw_text": "42. (A) made his head hurt                          (B) made his heart sing\n    (C) made him change his mind \t                  (D) made him give up baking\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
